import threading


class FizzBuzz:
    def __init__(self, n):
        self.n = n
        self.i = 1
        self.cv = threading.Condition()

    def _loop(self, mine, act):
        while True:
            with self.cv:
                self.cv.wait_for(lambda: self.i > self.n or mine(self.i))
                if self.i > self.n:
                    return
                act(self.i)
                self.i += 1
                self.cv.notify_all()

    def fizz(self, printFizz):
        self._loop(lambda i: i % 3 == 0 and i % 5 != 0, lambda i: printFizz())

    def buzz(self, printBuzz):
        self._loop(lambda i: i % 5 == 0 and i % 3 != 0, lambda i: printBuzz())

    def fizzbuzz(self, printFizzBuzz):
        self._loop(lambda i: i % 15 == 0, lambda i: printFizzBuzz())

    def number(self, printNumber):
        self._loop(lambda i: i % 3 != 0 and i % 5 != 0, printNumber)

