import threading


class FizzBuzz:
    def __init__(self, n):
        self.n = n
        self.fizz_gate = threading.Semaphore(0)
        self.buzz_gate = threading.Semaphore(0)
        self.fizzbuzz_gate = threading.Semaphore(0)
        self.number_gate = threading.Semaphore(1)

    def fizz(self, printFizz):
        for i in range(3, self.n + 1, 3):
            if i % 5 == 0:
                continue
            self.fizz_gate.acquire()
            printFizz()
            self.number_gate.release()

    def buzz(self, printBuzz):
        for i in range(5, self.n + 1, 5):
            if i % 3 == 0:
                continue
            self.buzz_gate.acquire()
            printBuzz()
            self.number_gate.release()

    def fizzbuzz(self, printFizzBuzz):
        for i in range(15, self.n + 1, 15):
            self.fizzbuzz_gate.acquire()
            printFizzBuzz()
            self.number_gate.release()

    def number(self, printNumber):
        for i in range(1, self.n + 1):
            self.number_gate.acquire()
            if i % 15 == 0:
                self.fizzbuzz_gate.release()
            elif i % 3 == 0:
                self.fizz_gate.release()
            elif i % 5 == 0:
                self.buzz_gate.release()
            else:
                printNumber(i)
                self.number_gate.release()
